import React, { useState, useRef, useEffect } from "react";
import { motion, useInView } from "framer-motion";

const AnimatedSection = ({ children, style, delay = 0 }) => {
  const [isHovered, setIsHovered] = useState(false);
  const sectionRef = useRef(null);
  const isInView = useInView(sectionRef, { once: true, margin: "-100px" });

  const containerVariants = {
    hidden: { 
      opacity: 0, 
      y: 20,
      scale: 0.98
    },
    visible: { 
      opacity: 1, 
      y: 0,
      scale: 1,
      transition: {
        duration: 0.6,
        delay: delay,
        ease: [0.25, 0.46, 0.45, 0.94],
        staggerChildren: 0.1
      }
    }
  };

  const childVariants = {
    hidden: { 
      opacity: 0, 
      y: 15,
      scale: 0.98
    },
    visible: { 
      opacity: 1, 
      y: 0,
      scale: 1,
      transition: {
        duration: 0.4,
        ease: [0.25, 0.46, 0.45, 0.94]
      }
    }
  };

  return (
    <motion.section
      ref={sectionRef}
      variants={containerVariants}
      initial="hidden"
      animate={isInView ? "visible" : "hidden"}
      whileHover={{ 
        scale: 1.02,
        transition: { duration: 0.3, ease: "easeOut" }
      }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="relative cursor-pointer rounded-3xl shadow-lg hover:shadow-2xl transition-all duration-500 overflow-hidden group"
      style={{
        padding: "clamp(2rem, 6.18vw, 4rem)",
        maxWidth: "1400px",
        margin: "0 auto clamp(3rem, 9.46vh, 6rem)",
        background: isHovered 
          ? "linear-gradient(135deg, #072D42 0%, #0A3A5A 100%)" 
          : "linear-gradient(135deg, #FEFCFB 0%, #F5F3F0 100%)",
        ...style,
      }}
    >
      {/* Overlay decorativo con proporción áurea */}
      <motion.div
        className="absolute inset-0 opacity-0 group-hover:opacity-10 transition-opacity duration-500"
        style={{
          background: "radial-gradient(circle at 61.8% 38.2%, #F29E38 0%, transparent 70%)"
        }}
      />
      
      {/* Contenido con animaciones escalonadas */}
      <motion.div
        variants={childVariants}
        className="relative z-10"
        style={{
          color: isHovered ? "#FEFCFB" : "#464E59"
        }}
      >
        {children}
      </motion.div>

      {/* Borde decorativo con proporción áurea */}
      <motion.div
        className="absolute inset-0 rounded-3xl border-2 opacity-0 group-hover:opacity-100 transition-opacity duration-500"
        style={{
          borderColor: "#F29E38",
          borderWidth: "clamp(1px, 0.618vh, 3px)"
        }}
      />
    </motion.section>
  );
};

export default AnimatedSection;
